requires yq;
requires fs;
requires log;

fn main() -> i64 {
  yaml: string = fs.read_file("config.yaml");
  json: string = yq.to_json(yaml);
  fs.write_file("config.json", json);
  log.info("YAML -> JSON done");
  roundtrip: string = yq.from_json(json);
  fs.write_file("config-roundtrip.yaml", roundtrip);
  log.info("JSON -> YAML roundtrip done");
  return 0;
}

